import numpy as np

def validar(arr):
    if arr.ndim != 1 or arr.dtype != np.float64:
        raise ValueError("expected 1d float64")
    return f"ok {arr.size}"

partes = []
try:
    partes.append(validar(np.array([1.0, 2.0], dtype=np.float64)))
except ValueError as e:
    partes.append(f"err {e}")
try:
    partes.append(validar(np.array([[1.0, 2.0]], dtype=np.float64)))
except ValueError as e:
    partes.append(f"err {e}")
print(" | ".join(partes))

